/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements the NotificationAdapter interface so it can be registered
 * with the NotificationService. Provides:
 * - Template rendering: generates HTML email bodies per notification type
 * - Recipient validation: validates email format before sending
 * - Configurable transport: accepts an EmailTransport for actual delivery
 *   (defaults to an in-memory store for testing)
 *
 * Architecture: All notifications flow through EventBus → NotificationService
 * → this adapter. Do NOT call send() directly from services.
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents a rendered email ready for delivery.
 */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  htmlBody: string;
  sentAt: Date;
}

/**
 * Transport interface for pluggable email delivery backends.
 * Implement this to integrate with SendGrid, SES, SMTP, etc.
 */
export interface EmailTransport {
  sendMail(email: SentEmail): Promise<{ success: boolean; error?: string }>;
}

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** Sender address shown in the "From" field. */
  fromAddress: string;
  /** Application name used in templates. */
  appName: string;
  /** Optional custom transport. Defaults to in-memory store. */
  transport?: EmailTransport;
}

const DEFAULT_CONFIG: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  appName: 'TaskFlow Pro',
};

/**
 * Email templates keyed by notification type.
 * Each template receives the payload and config, and returns an HTML string.
 */
const EMAIL_TEMPLATES: Record<
  NotificationType,
  (payload: NotificationPayload, config: EmailAdapterConfig) => string
> = {
  'order-confirmation': (payload, config) => {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    return [
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">`,
      `  <h2>Order Confirmation</h2>`,
      `  <p>Hi there,</p>`,
      `  <p>Your order <strong>${orderId}</strong> has been placed successfully.</p>`,
      `  <p>${payload.body}</p>`,
      `  <hr>`,
      `  <p style="color: #666; font-size: 12px;">`,
      `    This email was sent by ${config.appName}. Please do not reply.`,
      `  </p>`,
      `</div>`,
    ].join('\n');
  },

  'order-status-update': (payload, config) => {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    const newStatus = (payload.metadata?.newStatus as string) ?? 'unknown';
    return [
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">`,
      `  <h2>Order Update</h2>`,
      `  <p>Your order <strong>${orderId}</strong> is now <strong>${newStatus}</strong>.</p>`,
      `  <p>${payload.body}</p>`,
      `  <hr>`,
      `  <p style="color: #666; font-size: 12px;">`,
      `    This email was sent by ${config.appName}. Please do not reply.`,
      `  </p>`,
      `</div>`,
    ].join('\n');
  },

  welcome: (payload, config) => {
    return [
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">`,
      `  <h2>Welcome to ${config.appName}!</h2>`,
      `  <p>${payload.body}</p>`,
      `  <p>If you have any questions, feel free to reach out to our support team.</p>`,
      `  <hr>`,
      `  <p style="color: #666; font-size: 12px;">`,
      `    This email was sent by ${config.appName}. Please do not reply.`,
      `  </p>`,
      `</div>`,
    ].join('\n');
  },

  'account-updated': (payload, config) => {
    return [
      `<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">`,
      `  <h2>Account Updated</h2>`,
      `  <p>${payload.body}</p>`,
      `  <p>If you did not make this change, please contact support immediately.</p>`,
      `  <hr>`,
      `  <p style="color: #666; font-size: 12px;">`,
      `    This email was sent by ${config.appName}. Please do not reply.`,
      `  </p>`,
      `</div>`,
    ].join('\n');
  },
};

/**
 * Simple email address format validation.
 */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

/**
 * In-memory email transport for testing and development.
 */
export class InMemoryTransport implements EmailTransport {
  private emails: SentEmail[] = [];

  async sendMail(email: SentEmail): Promise<{ success: boolean; error?: string }> {
    this.emails.push(email);
    return { success: true };
  }

  getSentEmails(): SentEmail[] {
    return [...this.emails];
  }

  clear(): void {
    this.emails = [];
  }
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;

  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private transport: EmailTransport;
  private sentEmails: SentEmail[] = [];

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.transport = this.config.transport ?? new InMemoryTransport();
  }

  /**
   * Render an HTML email body from the notification payload using templates.
   */
  renderTemplate(payload: NotificationPayload): string {
    const templateFn = EMAIL_TEMPLATES[payload.type];
    return templateFn(payload, this.config);
  }

  /**
   * Validate and resolve the recipient email address.
   * Returns the validated email or throws if invalid.
   */
  resolveRecipient(recipient: string): string {
    const trimmed = recipient.trim().toLowerCase();
    if (!isValidEmail(trimmed)) {
      throw new Error(`Invalid email address: ${recipient}`);
    }
    return trimmed;
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    // Validate recipient
    let resolvedRecipient: string;
    try {
      resolvedRecipient = this.resolveRecipient(payload.recipient);
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : 'Invalid recipient';
      this.logger.error(`Recipient validation failed: ${errorMsg}`);
      return {
        success: false,
        notification: payload,
        deliveredAt: new Date(),
        error: errorMsg,
      };
    }

    // Render template
    const htmlBody = this.renderTemplate(payload);

    const email: SentEmail = {
      to: resolvedRecipient,
      subject: payload.subject,
      body: payload.body,
      htmlBody,
      sentAt: new Date(),
    };

    // Deliver via transport
    const transportResult = await this.transport.sendMail(email);
    if (!transportResult.success) {
      this.logger.error(`Transport failed: ${transportResult.error}`);
      return {
        success: false,
        notification: payload,
        deliveredAt: new Date(),
        error: transportResult.error ?? 'Transport delivery failed',
      };
    }

    this.sentEmails.push(email);

    return {
      success: true,
      notification: payload,
      deliveredAt: email.sentAt,
    };
  }

  /**
   * Get all successfully sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  type EmailTransport,
  type SentEmail,
} from '../../src/adapters/email.adapter.js';
import type {
  NotificationPayload,
  NotificationType,
} from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date(),
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter({ transport });
  });

  describe('channel', () => {
    it('should report email as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('send', () => {
    it('should send an email successfully', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notification).toBe(payload);
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store sent email with correct fields', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const emails = adapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]!.to).toBe('alice@example.com');
      expect(emails[0]!.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]!.body).toContain('Widget x2');
      expect(emails[0]!.htmlBody).toContain('<h2>Order Confirmation</h2>');
    });

    it('should deliver via the transport', async () => {
      await adapter.send(makePayload());
      expect(transport.getSentEmails()).toHaveLength(1);
    });

    it('should normalize recipient email to lowercase', async () => {
      const payload = makePayload({ recipient: 'Alice@Example.COM' });
      await adapter.send(payload);

      const emails = adapter.getSentEmails();
      expect(emails[0]!.to).toBe('alice@example.com');
    });

    it('should trim whitespace from recipient', async () => {
      const payload = makePayload({ recipient: '  alice@example.com  ' });
      await adapter.send(payload);

      const emails = adapter.getSentEmails();
      expect(emails[0]!.to).toBe('alice@example.com');
    });
  });

  describe('recipient validation', () => {
    it('should fail for empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should fail for recipient without @', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should fail for recipient without domain', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user@' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should not store email on validation failure', async () => {
      await adapter.send(makePayload({ recipient: 'bad' }));
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('template rendering', () => {
    it('should render order-confirmation template', () => {
      const payload = makePayload({
        type: 'order-confirmation',
        metadata: { orderId: 'order-42' },
      });
      const html = adapter.renderTemplate(payload);

      expect(html).toContain('Order Confirmation');
      expect(html).toContain('order-42');
      expect(html).toContain('TaskFlow Pro');
    });

    it('should render order-status-update template', () => {
      const payload = makePayload({
        type: 'order-status-update',
        metadata: { orderId: 'order-7', newStatus: 'shipped' },
      });
      const html = adapter.renderTemplate(payload);

      expect(html).toContain('Order Update');
      expect(html).toContain('order-7');
      expect(html).toContain('shipped');
    });

    it('should render welcome template', () => {
      const payload = makePayload({
        type: 'welcome',
        body: 'Your account has been created.',
      });
      const html = adapter.renderTemplate(payload);

      expect(html).toContain('Welcome to TaskFlow Pro');
      expect(html).toContain('Your account has been created.');
    });

    it('should render account-updated template', () => {
      const payload = makePayload({
        type: 'account-updated',
        body: 'Your email was changed.',
      });
      const html = adapter.renderTemplate(payload);

      expect(html).toContain('Account Updated');
      expect(html).toContain('Your email was changed.');
      expect(html).toContain('contact support');
    });

    it('should use custom appName in templates', () => {
      const customAdapter = new EmailAdapter({
        appName: 'MyApp',
        transport,
      });
      const payload = makePayload({ type: 'welcome' });
      const html = customAdapter.renderTemplate(payload);

      expect(html).toContain('Welcome to MyApp');
    });
  });

  describe('transport failure', () => {
    it('should return failure when transport rejects', async () => {
      const failingTransport: EmailTransport = {
        async sendMail(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'SMTP connection refused' };
        },
      };
      const failAdapter = new EmailAdapter({ transport: failingTransport });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should not store email on transport failure', async () => {
      const failingTransport: EmailTransport = {
        async sendMail(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'timeout' };
        },
      };
      const failAdapter = new EmailAdapter({ transport: failingTransport });

      await failAdapter.send(makePayload());
      expect(failAdapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return empty array initially', () => {
      expect(adapter.getSentEmails()).toEqual([]);
    });

    it('should return copies (not mutable references)', async () => {
      await adapter.send(makePayload());
      const first = adapter.getSentEmails();
      const second = adapter.getSentEmails();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('resolveRecipient', () => {
    it('should return lowercase trimmed email', () => {
      expect(adapter.resolveRecipient('  BOB@Example.Com  ')).toBe('bob@example.com');
    });

    it('should throw for invalid email', () => {
      expect(() => adapter.resolveRecipient('nope')).toThrow('Invalid email address');
    });
  });
});

describe('InMemoryTransport', () => {
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
  });

  it('should store sent emails', async () => {
    const email: SentEmail = {
      to: 'test@example.com',
      subject: 'Test',
      body: 'Hello',
      htmlBody: '<p>Hello</p>',
      sentAt: new Date(),
    };
    const result = await transport.sendMail(email);

    expect(result.success).toBe(true);
    expect(transport.getSentEmails()).toHaveLength(1);
    expect(transport.getSentEmails()[0]!.to).toBe('test@example.com');
  });

  it('should clear emails', async () => {
    await transport.sendMail({
      to: 'a@b.com',
      subject: 's',
      body: 'b',
      htmlBody: '<p>b</p>',
      sentAt: new Date(),
    });
    transport.clear();
    expect(transport.getSentEmails()).toHaveLength(0);
  });
});
